    39→NPY_NO_EXPORT PyObject *
    40→_PyArray_ArgMinMaxCommon(PyArrayObject *op,
    41→        int axis, PyArrayObject *out, int keepdims,
    42→        npy_bool is_argmax)
    43→{
    44→    PyArrayObject *ap = NULL, *rp = NULL;
    45→    PyArray_ArgFunc* arg_func = NULL;
    46→    char *ip, *func_name;
    47→    npy_intp *rptr;
    48→    npy_intp i, n, m;
    49→    int elsize;
    50→    // Keep a copy because axis changes via call to PyArray_CheckAxis
    51→    int axis_copy = axis;
    52→    npy_intp _shape_buf[NPY_MAXDIMS];
    53→    npy_intp *out_shape;
    54→    // Keep the number of dimensions and shape of
    55→    // original array. Helps when `keepdims` is True.
    56→    npy_intp* original_op_shape = PyArray_DIMS(op);
    57→    int out_ndim = PyArray_NDIM(op);
    58→    NPY_BEGIN_THREADS_DEF;
    59→
    60→    if ((ap = (PyArrayObject *)PyArray_CheckAxis(op, &axis, 0)) == NULL) {
    61→        return NULL;
    62→    }
    63→    /*
    64→     * We need to permute the array so that axis is placed at the end.
    65→     * And all other dimensions are shifted left.
    66→     */
    67→    if (axis != PyArray_NDIM(ap)-1) {
    68→        PyArray_Dims newaxes;
    69→        npy_intp dims[NPY_MAXDIMS];
    70→        int j;
    71→
    72→        newaxes.ptr = dims;
    73→        newaxes.len = PyArray_NDIM(ap);
    74→        for (j = 0; j < axis; j++) {
    75→            dims[j] = j;
    76→        }
    77→        for (j = axis; j < PyArray_NDIM(ap) - 1; j++) {
    78→            dims[j] = j + 1;
    79→        }
    80→        dims[PyArray_NDIM(ap) - 1] = axis;
    81→        op = (PyArrayObject *)PyArray_Transpose(ap, &newaxes);
    82→        Py_DECREF(ap);
    83→        if (op == NULL) {
    84→            return NULL;
    85→        }
    86→    }
    87→    else {
    88→        op = ap;
    89→    }
    90→
    91→    // Will get native-byte order contiguous copy.
    92→    PyArray_Descr *descr = NPY_DT_CALL_ensure_canonical(PyArray_DESCR(op));
    93→    if (descr == NULL) {
    94→        return NULL;
    95→    }
    96→    ap = (PyArrayObject *)PyArray_FromArray(op, descr, NPY_ARRAY_DEFAULT);
    97→
    98→    Py_DECREF(op);
    99→    if (ap == NULL) {
   100→        return NULL;
   101→    }
   102→
   103→    // Decides the shape of the output array.
   104→    if (!keepdims) {
   105→        out_ndim = PyArray_NDIM(ap) - 1;
   106→        out_shape = PyArray_DIMS(ap);
   107→    }
   108→    else {
   109→        out_shape = _shape_buf;
   110→        if (axis_copy == NPY_RAVEL_AXIS) {
   111→            for (int i = 0; i < out_ndim; i++) {
   112→                out_shape[i] = 1;
   113→            }
   114→        }
   115→        else {
   116→            /*
   117→             * While `ap` may be transposed, we can ignore this for `out` because the
   118→             * transpose only reorders the size 1 `axis` (not changing memory layout).
   119→             */
   120→            memcpy(out_shape, original_op_shape, out_ndim * sizeof(npy_intp));
   121→            out_shape[axis] = 1;
   122→        }
   123→    }
   124→
   125→    if (is_argmax) {
   126→        func_name = "argmax";
   127→        arg_func = PyDataType_GetArrFuncs(PyArray_DESCR(ap))->argmax;
   128→    }
   129→    else {
   130→        func_name = "argmin";
   131→        arg_func = PyDataType_GetArrFuncs(PyArray_DESCR(ap))->argmin;
   132→    }
   133→    if (arg_func == NULL) {
   134→        PyErr_SetString(PyExc_TypeError,
   135→                "data type not ordered");
   136→        goto fail;
   137→    }
   138→    elsize = PyArray_ITEMSIZE(ap);
   139→    m = PyArray_DIMS(ap)[PyArray_NDIM(ap)-1];
   140→    if (m == 0) {
   141→        PyErr_Format(PyExc_ValueError,
   142→                    "attempt to get %s of an empty sequence",
   143→                    func_name);
   144→        goto fail;
   145→    }
   146→
   147→    if (!out) {
   148→        rp = (PyArrayObject *)PyArray_NewFromDescr(
   149→                Py_TYPE(ap), PyArray_DescrFromType(NPY_INTP),
   150→                out_ndim, out_shape, NULL, NULL,
   151→                0, (PyObject *)ap);
   152→        if (rp == NULL) {
   153→            goto fail;
   154→        }
   155→    }
   156→    else {
   157→        if ((PyArray_NDIM(out) != out_ndim) ||
   158→                !PyArray_CompareLists(PyArray_DIMS(out), out_shape,
   159→                                        out_ndim)) {
   160→            PyErr_Format(PyExc_ValueError,
   161→                    "output array does not match result of np.%s.",
   162→                    func_name);
   163→            goto fail;
   164→        }
   165→        rp = (PyArrayObject *)PyArray_FromArray(out,
   166→                              PyArray_DescrFromType(NPY_INTP),
   167→                              NPY_ARRAY_CARRAY | NPY_ARRAY_WRITEBACKIFCOPY);
   168→        if (rp == NULL) {
   169→            goto fail;
   170→        }
   171→    }
   172→
   173→    NPY_BEGIN_THREADS_DESCR(PyArray_DESCR(ap));
   174→    n = PyArray_SIZE(ap)/m;
   175→    rptr = (npy_intp *)PyArray_DATA(rp);
   176→    for (ip = PyArray_DATA(ap), i = 0; i < n; i++, ip += elsize*m) {
   177→        arg_func(ip, m, rptr, ap);
   178→        rptr += 1;
   179→    }
   180→    NPY_END_THREADS_DESCR(PyArray_DESCR(ap));
   181→
   182→    Py_DECREF(ap);
   183→    /* Trigger the WRITEBACKIFCOPY if necessary */
   184→    if (out != NULL && out != rp) {
   185→        PyArray_ResolveWritebackIfCopy(rp);
   186→        Py_DECREF(rp);
   187→        rp = out;
   188→        Py_INCREF(rp);
   189→    }
   190→    return (PyObject *)rp;
   191→
   192→ fail:
   193→    Py_DECREF(ap);
   194→    Py_XDECREF(rp);
   195→    return NULL;
   196→}
